12	/**
13	 * Validates the authorization of an incoming request using a timing-safe comparison
14	 * of the cron secret header against the stored secret.
15	 *
16	 * This function performs a constant-time comparison to prevent timing attacks by:
17	 * 1. Retrieving the stored CRON_SECRET from the application secrets
18	 * 2. Extracting the x-cron-secret header from the request
19	 * 3. Comparing both values using a timing-safe equality check
20	 *
21	 * @param request - The incoming NextRequest object containing the authorization header
22	 * @returns `true` if the request is authorized (secrets match), `false` otherwise
23	 *
24	 * @remarks
25	 * - Returns `false` if either the secret or header is missing/empty
26	 * - Returns `false` if the secret and header have different lengths
27	 * - Uses `timingSafeEqual` to prevent timing-based attacks
28	 */
29	const isAuthorized = (request: NextRequest) => {
30	    const secret = getSecrets().CRON_SECRET?.trim() ?? '';
31	    const header = request.headers.get('x-cron-secret')?.trim() ?? '';
32	
33	    if (!secret || !header) {
34	        return false;
35	    }
36	
