import { timingSafeEqual } from 'crypto';
import { revalidatePath } from 'next/cache';
import { NextRequest, NextResponse } from 'next/server';

import { buildJsonErrorResponse } from '@/lib/api';
import { triggerInvitationsCore } from '@/lib/core/triggerInvitations';
import { broadcast } from '@/lib/events';
import { getSecrets } from '@/lib/secrets';
import { NewGameInputSchema } from '@/types/actions/TriggerInvitations';
import { FootyChannel } from '@/types/FootyChannel';

/**
 * Validates the authorization of an incoming request using a timing-safe comparison
 * of the cron secret header against the stored secret.
 *
 * This function performs a constant-time comparison to prevent timing attacks by:
 * 1. Retrieving the stored CRON_SECRET from the application secrets
 * 2. Extracting the x-cron-secret header from the request
 * 3. Comparing both values using a timing-safe equality check
 *
 * @param request - The incoming NextRequest object containing the authorization header
 * @returns `true` if the request is authorized (secrets match), `false` otherwise
 *
 * @remarks
 * - Returns `false` if either the secret or header is missing/empty
 * - Returns `false` if the secret and header have different lengths
 * - Uses `timingSafeEqual` to prevent timing-based attacks
 */
const isAuthorized = (request: NextRequest) => {
    const secret = getSecrets().CRON_SECRET?.trim() ?? '';
    const header = request.headers.get('x-cron-secret')?.trim() ?? '';

    if (!secret || !header) {
        return false;
    }

    const secretBuffer = Buffer.from(secret);
    const headerBuffer = Buffer.from(header);
    if (secretBuffer.length !== headerBuffer.length) {
        return false;
    }

    return timingSafeEqual(secretBuffer, headerBuffer);
};

/**
 * Handles POST requests to send footy game invitations.
 *
 * This endpoint requires authorization and processes optional parameters for overriding
 * time checks and including custom messages in invitations.
 *
 * @param request - The Next.js request object containing the HTTP request data
 * @returns A JSON response with the invitation decision and HTTP status code
 *
 * @throws {401} When the request is not authorized
 *
 * @remarks
 * The request body may optionally include:
 * - `overrideTimeCheck`: Boolean to bypass time-based invitation restrictions
 * - `customMessage`: String containing a custom message to include with the invitation
 *
 * If the request body is invalid or missing, default values are used (overrideTimeCheck: false, customMessage: null)
 */
export const POST = async (request: NextRequest) => {
    if (!isAuthorized(request)) {
        return NextResponse.json({ message: 'Unauthorized' }, { status: 401 });
    }

    try {
        let overrideTimeCheck = false;
        let customMessage: string | undefined;

        const body: unknown = await request.json().catch(() => null);
        if (body) {
            const parsed = NewGameInputSchema.partial().safeParse(body);
            if (parsed.success) {
                overrideTimeCheck = parsed.data.overrideTimeCheck ?? false;
                customMessage = parsed.data.customMessage?.trim();
            }
        }

        const decision = await triggerInvitationsCore({
            overrideTimeCheck,
            customMessage: customMessage ?? '',
        });

        revalidatePath('/footy/admin/newgame');
        revalidatePath('/footy/admin/responses');
        revalidatePath('/footy/admin/picker');
        revalidatePath('/footy/response');
        broadcast(FootyChannel.Invitations);

        return NextResponse.json(decision, { status: 200 });
    } catch (error) {
        return buildJsonErrorResponse(error, 'Failed to trigger invitations.');
    }
};

import * as path from 'node:path';

import { defineConfig, devices } from '@playwright/test';
import * as dotenv from 'dotenv';

/* CI uses port 3000 (no dev server conflict); local uses 3002 so playwright and
   the regular dev server can run simultaneously without clashing. */
const BASE_URL = process.env.CI ? 'http://127.0.0.1:3000' : 'http://127.0.0.1:3002';

/* Load playwright-specific env vars for local runs (no 1Password needed). CI
   sets its own env vars directly; we don't want to override them. */
if (!process.env.CI) {
    dotenv.config({ path: path.join(__dirname, '.env.playwright'), override: true });
}

/**
 * See https://playwright.dev/docs/test-configuration.
 */
export default defineConfig({
    globalSetup: './e2e/global-setup.ts',
    testDir: './e2e',

    /* Fail the build on CI if you accidentally left test.only in the source code. */
    forbidOnly: !!process.env.CI,
    /* Never retry: I don't want flaky tests to hide real issues */
    retries: 0,
    /* Opt out of parallel tests. */
    workers: 1,
    /* Reporter to use. See https://playwright.dev/docs/test-reporters */
    reporter: process.env.CI ?
        [
            ['github'],
            ['html', { open: 'never' }],
        ] :
        [['html', { open: 'on-failure' }]],

    /* Shared settings for all the projects below. See
    https://playwright.dev/docs/api/class-testoptions. */
    use: {
        /* Base URL to use in actions like `await page.goto('/')`. */
        baseURL: BASE_URL,

        /* Collect trace when retrying the failed test. See
        https://playwright.dev/docs/trace-viewer */
        trace: 'on-first-retry',

        /* I want to see screenshots only on failure */
        screenshot: 'only-on-failure',

        /* For figuring out what went wrong with failed or flaky tests, like the
        drinkers page in Firefox */
        video: 'retain-on-failure',
    },

    /* Configure projects for major browsers.
     *
     * There is deliberately no per-project database reseeding here. An
     * earlier attempt reseeded via a project `teardown` between each browser,
     * but Playwright schedules all zero-dependency projects into the same
     * phase and only runs their teardowns afterwards as the next phase - so
     * the reseed landed once at the very end of the run, not between browsers.
     * Chaining browsers together with `dependencies` to force separate phases
     * doesn't work either: Playwright rejects a project depending on another
     * project's teardown. Rather than fight the scheduler, tests that mutate
     * shared fixture data (e.g. e2e/newgame.spec.ts) are responsible for not
     * assuming a pristine starting state - see that file for how it avoids
     * depending on whether a given player has already responded to the
     * current game. globalSetup seeds once before the whole run. */
    projects: [
        {
            name: 'chromium',
            use: { ...devices['Desktop Chrome'] },
        },

        {
            name: 'firefox',
            use: { ...devices['Desktop Firefox'] },
        },

        {
            name: 'webkit',
            use: { ...devices['Desktop Safari'] },
        },

        {
            name: 'mobile',
            use: { viewport: { width: 375, height: 667 } },
        },
        {
            name: 'tablet',
            use: { viewport: { width: 768, height: 1024 } },
        },

        /* Test against branded browsers. */
        // {
        //   name: 'Microsoft Edge',
        //   use: { ...devices['Desktop Edge'], channel: 'msedge' },
        // },
        // {
        //   name: 'Google Chrome',
        //   use: { ...devices['Desktop Chrome'], channel: 'chrome' },
        // },
    ],

    /* Start a fresh production server before each test run. */
    webServer: {
        command: process.env.CI ? 'npm run start:ci' : 'npm run start:playwright',
        url: BASE_URL,
        stdout: 'pipe',
        stderr: 'pipe',
        reuseExistingServer: false,
    },
});

